import { useGLTF } from "@react-three/drei";
import { useLayoutEffect } from "react";
import * as THREE from "three";

export function Model() {
  const modelPath = "http://localhost:3000/public/uploads/3dmodels/ferrari_f8_tributo.glb";
  const { scene } = useGLTF(modelPath);

  // Center the model and adjust position
  useLayoutEffect(() => {
    const box = new THREE.Box3().setFromObject(scene);
    const center = box.getCenter(new THREE.Vector3());
    scene.position.sub(center);
    scene.position.y = -0.5; // Adjust this value based on your model's height
  }, [scene]);

  return (
    <group position={[0, -1, 0]}>
      <primitive
        object={scene}
        scale={0.8}
        rotation={[0, Math.PI / 4, 0]}
      />
      {/* Add ground plane */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -1, 0]}>
        <planeGeometry args={[20, 20]} />
        <meshStandardMaterial color="#404040" />
      </mesh>
    </group>
  );
}

// Preload the model
useGLTF.preload("http://localhost:3000/public/uploads/3dmodels/ferrari_f8_tributo.glb");
